// Parse the task tracker JSON from file content
const fileContent = $input.first().binary.data;
const text = Buffer.from(fileContent.data, 'base64').toString('utf8');
const tasks = JSON.parse(text);

// Get current date
const now = new Date();
const today = now.toISOString().split('T')[0];

// Filter for 48-hour urgent tasks that are not done
const urgentTasks = tasks.filter(t => 
  t.deadline_category === '48hrs' && 
  t.status !== 'done' && 
  t.status !== 'acknowledged'
);

// Also check for tasks with actual deadlines within 48 hours
const soonTasks = tasks.filter(t => {
  if (t.status === 'done' || t.status === 'acknowledged') return false;
  if (!t.deadline) return false;
  const deadline = new Date(t.deadline);
  const hoursUntil = (deadline - now) / (1000 * 60 * 60);
  return hoursUntil > 0 && hoursUntil <= 48;
});

// Combine and deduplicate
const allUrgent = [...urgentTasks, ...soonTasks];
const seen = new Set();
const unique = allUrgent.filter(t => {
  if (seen.has(t.task_id)) return false;
  seen.add(t.task_id);
  return true;
});

if (unique.length === 0) {
  return []; // No urgent tasks — stay quiet
}

// Format task list for email
const taskList = unique.map(t => 
  `• [${t.task_id}] ${t.description} (Priority: ${t.priority}, Status: ${t.status})`
).join('\n');

return [{
  json: {
    hasUrgent: true,
    taskCount: unique.length,
    taskList: taskList,
    tasks: unique,
    checkedAt: now.toISOString()
  }
}];

// Parse the task tracker JSON
const fileContent = $input.first().binary.data;
const text = Buffer.from(fileContent.data, 'base64').toString('utf8');
const tasks = JSON.parse(text);

const now = new Date();

// Find overdue tasks (48hrs category that have been pending too long, or past deadline)
const overdueTasks = tasks.filter(t => {
  if (t.status === 'done' || t.status === 'acknowledged') return false;

  // Tasks marked 48hrs that are still pending
  if (t.deadline_category === '48hrs' && t.status === 'pending') return true;

  // Tasks with actual deadlines that have passed
  if (t.deadline) {
    const deadline = new Date(t.deadline);
    return deadline < now;
  }

  return false;
});

if (overdueTasks.length === 0) {
  return []; // Nothing overdue — stay quiet
}

const taskList = overdueTasks.map(t => 
  `• [${t.task_id}] ${t.description} (Priority: ${t.priority})`
).join('\n');

return [{
  json: {
    hasOverdue: true,
    taskCount: overdueTasks.length,
    taskList: taskList,
    tasks: overdueTasks,
    checkedAt: now.toISOString()
  }
}];

// Handle Jetson response or generate fallback digest
const input = $input.first().json;

let digestContent = '';

if (input.response) {
  // Jetson AI provided analysis
  digestContent = input.response;
} else {
  // Fallback: generate digest from task data directly
  digestContent = 'AI analysis unavailable this week. Here is the task summary:\n\n';
  digestContent += 'Please check the n8n dashboard for full task status.\n';
  digestContent += 'Jetson AI may be offline — the system will retry next week.';
}

const now = new Date();
const weekOf = now.toLocaleDateString('en-AU', { 
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
  timeZone: 'Australia/Brisbane'
});

return [{
  json: {
    digestContent: digestContent,
    weekOf: weekOf,
    generatedAt: now.toISOString(),
    jetsonAvailable: !!input.response
  }
}];

// Log this workflow execution
const now = new Date();
const trigger = $input.first().json;

const logEntry = {
  timestamp: now.toISOString(),
  workflow: 'bradix-core',
  trigger: $executionId,
  action: 'urgent_alert_sent',
  taskCount: trigger.taskCount || 0,
  details: trigger.taskList || 'No details'
};

console.log(JSON.stringify(logEntry));

return [{ json: logEntry }];

// Log weekly digest execution
const now = new Date();
const trigger = $input.first().json;

const logEntry = {
  timestamp: now.toISOString(),
  workflow: 'bradix-core',
  trigger: $executionId,
  action: 'weekly_digest_sent',
  jetsonAvailable: trigger.jetsonAvailable || false,
  weekOf: trigger.weekOf || 'unknown'
};

console.log(JSON.stringify(logEntry));

return [{ json: logEntry }];

// Log overdue escalation
const now = new Date();
const trigger = $input.first().json;

const logEntry = {
  timestamp: now.toISOString(),
  workflow: 'bradix-core',
  trigger: $executionId,
  action: 'overdue_escalation_sent',
  taskCount: trigger.taskCount || 0,
  details: trigger.taskList || 'No details'
};

console.log(JSON.stringify(logEntry));

return [{ json: logEntry }];

// Combine task filter results with AI analysis
const urgentData = $('Filter 48h Urgent Tasks').first().json;
const aiAnalysis = $input.first().json;

let enhancedList = urgentData.taskList || '';

if (aiAnalysis && aiAnalysis.analysis) {
  enhancedList += '\n\n--- AI Analysis ---\n' + aiAnalysis.analysis;
}

return [{
  json: {
    ...urgentData,
    taskList: enhancedList,
    aiEnhanced: !!aiAnalysis.analysis
  }
}];
